1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty grid for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two live cells each with one neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 0], [1, 0]])).toEqual([]);
13	  });
14	  it("should keep a live cell alive with two live neighbors (survival)", () => {
15	    expect(nextGeneration([[0, 0], [0, 1], [0, 2]])).toContainEqual([0, 1]);
16	  });
17	  it("should kill a live cell with four live neighbors (overpopulation)", () => {
18	    expect(
19	      nextGeneration([[1, 1], [1, 0], [0, 1], [2, 1], [1, 2]])
20	    ).not.toContainEqual([1, 1]);
21	  });
22	  it("should bring a dead cell to life with exactly three live neighbors (reproduction)", () => {
23	    expect(nextGeneration([[0, 0], [1, 0], [0, 1]])).toContainEqual([1, 1]);
24	  });
25	  it.todo("should oscillate a vertical blinker into a horizontal blinker");
26	  it.todo("should keep a block unchanged (still life)");
27	  it.todo("should handle negative coordinates");
28	});
29

1	type Cell = [number, number]; // [x, y]
2	
3	const NEIGHBOR_OFFSETS: Cell[] = [
4	  [-1, -1], [0, -1], [1, -1],
5	  [-1, 0], [1, 0],
6	  [-1, 1], [0, 1], [1, 1],
7	];
8	
9	const key = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const countLiveNeighbors = (cell: Cell, live: Set<string>): number =>
12	  NEIGHBOR_OFFSETS.filter(([dx, dy]) =>
13	    live.has(key([cell[0] + dx, cell[1] + dy]))
14	  ).length;
15	
16	const survives = (liveNeighbors: number): boolean =>
17	  liveNeighbors === 2 || liveNeighbors === 3;
18	
19	const isBorn = (liveNeighbors: number): boolean => liveNeighbors === 3;
20	
21	export function nextGeneration(cells: Cell[]): Cell[] {
22	  const live = new Set(cells.map(key));
23	  const candidates = new Map<string, Cell>();
24	  for (const cell of cells) {
25	    candidates.set(key(cell), cell);
26	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
27	      const neighbor: Cell = [cell[0] + dx, cell[1] + dy];
28	      candidates.set(key(neighbor), neighbor);
29	    }
30	  }
31	  return [...candidates.values()].filter((cell) => {
32	    const liveNeighbors = countLiveNeighbors(cell, live);
33	    return live.has(key(cell))
34	      ? survives(liveNeighbors)
35	      : isBorn(liveNeighbors);
36	  });
37	}
